SELECT

FROM ai_lowcode_model
WHERE tenant_id = #{tenantId}

  AND domain_id = #{domainId}


  AND (
    model_code LIKE CONCAT('%', #{keyword}, '%')
    OR model_name LIKE CONCAT('%', #{keyword}, '%')
    OR model_desc LIKE CONCAT('%', #{keyword}, '%')
  )


  AND status = #{status}


  AND master_data = #{masterData}

ORDER BY update_time DESC, id DESC

SELECT

FROM ai_lowcode_model
WHERE tenant_id = #{tenantId}

  AND domain_id = #{domainId}


  AND (
    model_code LIKE CONCAT('%', #{keyword}, '%')
    OR model_name LIKE CONCAT('%', #{keyword}, '%')
    OR model_desc LIKE CONCAT('%', #{keyword}, '%')
  )


  AND status = #{status}

ORDER BY domain_id ASC, model_name ASC, id ASC

SELECT

FROM ai_lowcode_model
WHERE tenant_id = #{tenantId}
  AND id = #{id}
LIMIT 1

SELECT

FROM ai_lowcode_model
WHERE tenant_id = #{tenantId}
  AND domain_id = #{domainId}
  AND model_code = #{modelCode}
LIMIT 1

SELECT

FROM ai_lowcode_model
WHERE tenant_id = #{tenantId}
  AND model_code = #{modelCode}
ORDER BY update_time DESC, id DESC
LIMIT 1

SELECT COUNT(1)
FROM ai_lowcode_model
WHERE tenant_id = #{tenantId}
  AND domain_id = #{domainId}
  AND model_code = #{modelCode}

  AND id != #{excludeId}
